# DK HVI.  Herning - Viborg
#
let hv = path("d3.dk.hvi");

with detail = 4, railway = :first :pax :removed {
    # point.dk.Herning  dk.HBV
 
    with link = "line.dk.HVI" {
        track(:station, hv[:her.yv, :her.yv + 1seg]);
        track(hv[:her.yv + 0.9seg, :her.xv + 2.01km]);
        line_label(:right:w, hv[:her.xv + 2km] >> 0.5mt, "HVI");
        track(hv[:her.xv + 1.99km, :nyb - 0.49sw]);
    }

    with link = "point.dk.Nybo", railway = :station {
        track(hv[:nyb - 0.5sw, :nyb + 0.5sw]);
        marker(:right :de.hst, hv[:nyb] >> 0.5mt);
        station(:right:left_align, hv[:nyb] >> 0.5mt >> 1sh + (1.4dt, 1.3dt),
            "Nybo", "HVI: 5,9"
        );
    }

    with link = "line.dk.HVI" {
        track(hv[:nyb + 0.49sw, :sun - 0.49sw]);
    }

    with link = "point.dk.Sunds", railway = :station {
        track(hv[:sun - 0.5sw, :sun + 0.5sw]);
        marker(:left :de.hp, hv[:sun] << 0.5mt);
        marker(:left :de.exbf, hv[:sun] << 0.5mt);
        label(hv[:sun] << 0.5mt << 1.4sh + (-2.1dt, 0.4dt),
            vbox(:right:base, span(:xsmall, "HVI: 8,9"), "Sunds") 
        );
    }

    with link = "line.dk.HVI" {
        track(hv[:sun + 0.49sw, :nor - 0.49sw]);
    }

    with link = "point.dk.Nørremark", railway = :station {
        track(hv[:nor - 0.5sw, :nor + 0.5sw]);
        marker(:right :de.hp, hv[:nor] >> 0.5mt);
        station(:right, hv[:nor] >> 0.5mt >> 1sh + (2dt, 1.9dt),
            "Nørremark", "HVI: 11,6"
        );
    }

    with link = "line.dk.HVI" {
        track(hv[:nor + 0.49sw, :ils - 0.49sw]);
    }

    with link = "point.dk.Ilskov", railway = :station {
        track(hv[:ils - 0.5sw, :ils + 0.5sw]);
        marker(:left :de.hp, hv[:ils] << 0.5mt);
        marker(:left :de.exbf, hv[:ils] << 0.5mt);
        station(:left:right_align,
            hv[:ils] << 0.5mt << 1.4sh + (-2dt, 0.8dt),
            "Ilskov", "HVI: 15,0 "
        );
    }

    with link = "line.dk.HVI" {
        track(hv[:ils + 0.49sw, :ils + 2.71km]);
        line_label(:right:w, hv[:ils + 2.7km] >> 0.5mt, (0dt, 0.2dt), "HVI");
        track(hv[:ils + 2.69km, :ged - 0.49sw]);
    }

    with link = "point.dk.Gedhus", railway = :station {
        track(hv[:ged - 0.5sw, :ged + 0.5sw]);
        marker(:left :de.hp, hv[:ged] << 0.5mt);
        station(:left, hv[:ged] << 0.5mt << 1sh + (-2dt, 1dt),
            "Gedhus", "HVI: 19,8"
        );
    }

    with link = "line.dk.HVI" {
        track(hv[:ged + 0.49sw, :gro - 0.49sw]);
    }

    with link = "point.dk.Grove", railway = :station {
        track(hv[:gro - 0.5sw, :gro + 0.5sw]);
        marker(:left :de.anst, hv[:gro] << 0.5mt);
        station(:left:right_align, hv[:gro] << 0.5mt << 1sh + (-1.5dt, 0.7dt),
            span(:small, "Grove"), "HVI: 21,5 "
        );
    }

    with link = "line.dk.HVI" {
        track(hv[:gro + 0.49sw, :kol - 0.49sw]);
    }

    with link = "point.dk.Kølvrå", railway = :station {
        track(hv[:kol - 0.5sw, :kol + 0.5sw]);
        marker(:right :de.bf, hv[:kol] >> 0.5mt);
        station(:right:left_align, hv[:kol] >> 0.5mt >> 1sh + (2dt, 1.8dt),
            vbox(:left:base,
                hbox(:left:base, " ", span(:former, "Grove")),
                "Kølvrå"
            ),
            "HVI: 22,1"
        );
    }

    with link = "line.dk.HVI" {
        track(hv[:kol + 0.49sw, :kar - 0.49sw]);
    }

    with link = "point.dk.Karup", railway = :station {
        track(hv[:kar - 0.5sw, :kar + 0.5sw]);
        marker(:right :de.bf, hv[:kar] >> 0.5mt);
        station(:bottom, hv[:kar] >> 0.5mt >> 1sh + (0.3dt, 0.8dt),
            "Karup", "HVI: 24,3"
        );
    }

    with link = "line.dk.HVI" {
        track(hv[:kar + 0.49sw, :kar + 4.61km]);
        line_label(:left:se, hv[:kar + 4.6km] << 0.5mt, "HVI");
        track(hv[:kar + 4.59km, :fre - 0.49sw]);
    }

    with link = "point.dk.Frederiks", railway = :station {
        track(hv[:fre - 0.5sw, :fre + 0.5sw]);
        marker(:right :de.bf, hv[:fre] >> 0.5mt);
        station(:right, hv[:fre] >> 0.5mt >> 1sh + (2dt, 2.3dt),
            "Frederiks", "HVI: 30,5"
        );
    }

    with link = "line.dk.HVI" {
        track(hv[:fre + 0.49sw, :ske - 0.49sw]);
    }

    with link = "point.dk.Skelhøje", railway = :station {
        track(hv[:ske - 0.5sw, :ske + 0.5sw]);
        marker(:right :de.bf, hv[:ske] >> 0.5mt);
        station(:right, hv[:ske] >> 0.5mt >> 1sh + (1.8dt, 1.7dt),
            "Skelhøje", "HVI: 34,5"
        );
    }

    with link = "line.dk.HVI" {
        track(hv[:ske + 0.49sw, :bak - 0.49sw]);
    }

    with link = "point.dk.Bækkelund", railway = :station {
        track(hv[:bak - 0.5sw, :bak + 0.5sw]);
        marker(:right :de.hp, hv[:bak] >> 0.5mt);
        marker(:right :de.exbf, hv[:bak] >> 0.5mt);
        station(:bottom, hv[:bak] >> 0.5mt >> 1.4sh >> 0.8dt,
            "Bækkelund", "HVI: 40,2"
        );
    }

    with link = "line.dk.HVI" {
        track(hv[:bak + 0.49sw, :hal - 0.49sw]);
    }

    with link = "point.dk.Hald-Ege", railway = :station {
        track(hv[:hal - 0.5sw, :hal + 0.5sw]);
        marker(:left :de.hp, hv[:hal] << 0.5mt);
        label(hv[:hal] << 0.5mt << 1sh + (-1.8dt, 0.8dt),
            vbox(:right:base,
                span(:former, "Kuranstalten"),
                vbox(:center:topbase,
                    "Hald Ege",
                    span(:xsmall, "HVI: 42,2")
                )
            )
        );
    }

    with link = "line.dk.HVI" {
        track(hv[:hal + 0.49sw, :hal + 2.01km]);
        line_label(:left:se, hv[:hal + 2km] << 0.5mt, "HVI");
        track(hv[:hal + 1.99km, :vib.zh]);
        track(:ror:lor,
                hv[:vib.zh - 0.1dl, :vib.zh]
            ..  hv[:vib.xh, :vib.yf + 0.1dl] << 1mo
        );
        track(:ror:lor, hv[:vib.yf, :vib.yh + 0.1dl] << 1mo);
        track(:ror:lor, hv[:vib.yh, :vib - 399m] << 1mo);
    }
}


